 1	import React, { FC } from 'react';
 2	import { useFormContext } from 'react-hook-form';
 3	import { useNavigate } from 'react-router-dom-v5-compat';
 4	
 5	import { ActionGroup, Alert, AlertVariant, Button, ButtonVariant } from '@patternfly/react-core';
 6	import { useNetworkingTranslation } from '@utils/hooks/useNetworkingTranslation';
 7	import { isEmpty } from '@utils/utils';
 8	
 9	type RouteFormActionsProps = {
10	  apiError: Error;
11	};
12	
13	const RouteFormActions: FC<RouteFormActionsProps> = ({ apiError }) => {
14	  const { t } = useNetworkingTranslation();
15	  const navigate = useNavigate();
16	  const {
17	    formState: { isSubmitting, isValid },
18	  } = useFormContext();
19	
20	  return (
21	    <>
22	      {!isEmpty(apiError) && (
23	        <Alert isInline title={t('Error')} variant={AlertVariant.danger}>
24	          {apiError?.message}
25	        </Alert>
26	      )}
27	      <ActionGroup>
28	        <Button
29	          id="save-changes"
30	          isDisabled={!isValid || isSubmitting}
31	          isLoading={isSubmitting}
32	          type="submit"
33	          variant={ButtonVariant.primary}
34	        >
35	          {t('Create')}
36	        </Button>
37	        <Button
38	          id="cancel"
39	          onClick={() => navigate(-1)}
40	          type="button"
41	          variant={ButtonVariant.secondary}
42	        >
43	          {t('Cancel')}
44	        </Button>
45	      </ActionGroup>
46	    </>
47	  );
48	};
49	
50	export default RouteFormActions;

